.load extensions/tar/target/wasm32-wasip2/release/tar_extension.component.wasm

/* Smoke test for the `tar` extension.
 * Run via:  tooling/smoke.py tar
 *
 * Fixture: hand-built POSIX ustar archive with 2 entries
 *   hello.txt        (10 bytes "hello tar\n")  mode 0644, mtime 1700000000
 *   subdir/world.txt (6  bytes "world\n")      mode 0644, mtime 1700000000
 * + 1024-byte zero-block EOF. Total 3072 bytes (6 * 512).
 *
 * Stored in a TEMP TABLE so the blob is reusable across the per-
 * scalar SELECTs below (a CTE only scopes to one statement). */

CREATE TEMP TABLE archive(blob BLOB);
INSERT INTO archive VALUES (x'');

/* ─── tar_is_valid: 1 on a clean archive ─── */
SELECT tar_is_valid(blob) FROM archive;

/* ─── tar_entry_count: 2 entries ─── */
SELECT tar_entry_count(blob) FROM archive;

/* ─── tar_entry_names: JSON array in declaration order ─── */
SELECT tar_entry_names(blob) FROM archive;

/* ─── tar_entry_size: body byte count per entry ─── */
SELECT tar_entry_size(blob, 'hello.txt') FROM archive;
SELECT tar_entry_size(blob, 'subdir/world.txt') FROM archive;

/* ─── tar_entry_data: raw body bytes (hex for readability) ─── */
SELECT hex(tar_entry_data(blob, 'hello.txt')) FROM archive;
SELECT hex(tar_entry_data(blob, 'subdir/world.txt')) FROM archive;

/* ─── tar_entry_mtime: epoch seconds set at archive build ─── */
SELECT tar_entry_mtime(blob, 'hello.txt') FROM archive;
SELECT tar_entry_mtime(blob, 'subdir/world.txt') FROM archive;

/* ─── tar_entry_mode: 0644 == decimal 420 ─── */
SELECT tar_entry_mode(blob, 'hello.txt') FROM archive;
SELECT tar_entry_mode(blob, 'subdir/world.txt') FROM archive;

/* ─── tar_version: non-empty ─── */
SELECT length(tar_version()) > 0;

/* ─── failure cases ─── */
/* Random garbage bytes → tar_is_valid = 0. */
SELECT tar_is_valid(x'deadbeefcafebabe0102030405060708');

/* NULL blob → NULL passthrough on data scalars, 0 on is_valid. */
SELECT tar_entry_count(NULL);
SELECT tar_entry_names(NULL);
SELECT tar_is_valid(NULL);

/* Missing entry name in a valid archive → NULL. */
SELECT tar_entry_size(blob, 'does-not-exist.txt') FROM archive;
SELECT tar_entry_data(blob, 'does-not-exist.txt') FROM archive;
SELECT tar_entry_mtime(blob, 'does-not-exist.txt') FROM archive;
SELECT tar_entry_mode(blob, 'does-not-exist.txt') FROM archive;
